const W = 580, H = 300;
const layer = state.layer || 12;
const threshold = state.threshold || 0.25;
const totalNeurons = 40;
const rewiredCount = Math.round(totalNeurons * (0.08 + layer / 100));
const cols = 10;

ctx.fillStyle = '#1a1a2e'; ctx.fillRect(0, 0, W, H);

// Title
ctx.fillStyle = '#e0e0e0'; ctx.font = 'bold 14px sans-serif'; ctx.textAlign = 'center';
ctx.fillText(`Layer ${layer} — FFN Neurons (${Math.round(rewiredCount/totalNeurons*100)}% rewired for action)`, W/2, 25);

// Draw neurons
for (let i = 0; i < totalNeurons; i++) {
  const col = i % cols, row = Math.floor(i / cols);
  const x = 90 + col * 42, y = 50 + row * 55;
  const isRewired = i < rewiredCount;
  ctx.beginPath(); ctx.arc(x, y, 16, 0, Math.PI*2);
  ctx.fillStyle = isRewired ? '#f43f5e' : '#3b82f6';
  ctx.globalAlpha = isRewired ? 0.9 : 0.5;
  ctx.fill(); ctx.globalAlpha = 1;
  ctx.strokeStyle = isRewired ? '#fbbf24' : '#1e40af';
  ctx.lineWidth = isRewired ? 2.5 : 1;
  ctx.stroke();
}

// Legend
ctx.font = '12px sans-serif'; ctx.textAlign = 'left';
ctx.fillStyle = '#3b82f6'; ctx.fillRect(90, H-35, 12, 12);
ctx.fillStyle = '#94a3b8'; ctx.fillText('Semantic (unchanged)', 108, H-24);
ctx.fillStyle = '#f43f5e'; ctx.fillRect(280, H-35, 12, 12);
ctx.fillStyle = '#94a3b8'; ctx.fillText('Action-rewired', 298, H-24);

ctx.fillStyle = '#64748b'; ctx.font = '11px sans-serif';
ctx.fillText('← Drag slider to explore layers →', W/2 - 80, H-5);

const W = 580, H = 280;
ctx.fillStyle = '#1a1a2e'; ctx.fillRect(0, 0, W, H);

const steps = [
  { label: 'Base VLM', desc: 'Rich semantic representations', color: '#3b82f6', icon: '🧠' },
  { label: 'VLA Fine-tune', desc: 'Add action tokens + training', color: '#8b5cf6', icon: '🤖' },
  { label: 'Weight Diff', desc: 'Find rewired neurons (<25%)', color: '#f59e0b', icon: '🔍' },
  { label: 'SAE Decompose', desc: 'Extract sparse features', color: '#10b981', icon: '🧬' },
  { label: 'Cluster', desc: 'Group into operator candidates', color: '#f43f5e', icon: '🎯' }
];

const activeStep = state.step || 0;

steps.forEach((s, i) => {
  const x = 30 + i * 112, y = 60;
  const isActive = i <= activeStep;

  // Arrow
  if (i > 0) {
    ctx.strokeStyle = i <= activeStep ? '#fbbf24' : '#334155';
    ctx.lineWidth = 2;
    ctx.beginPath(); ctx.moveTo(x - 20, y + 25); ctx.lineTo(x - 5, y + 25); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(x - 10, y + 20); ctx.lineTo(x - 5, y + 25); ctx.lineTo(x - 10, y + 30); ctx.stroke();
  }

  // Box
  ctx.fillStyle = isActive ? s.color + '33' : '#0f172a';
  ctx.strokeStyle = isActive ? s.color : '#334155';
  ctx.lineWidth = isActive ? 2 : 1;
  ctx.beginPath(); ctx.roundRect(x, y, 95, 50, 8); ctx.fill(); ctx.stroke();

  ctx.fillStyle = isActive ? '#f1f5f9' : '#64748b';
  ctx.font = 'bold 12px sans-serif'; ctx.textAlign = 'center';
  ctx.fillText(s.icon + ' ' + s.label, x + 47, y + 22);
  ctx.font = '9px sans-serif';
  ctx.fillText(s.desc, x + 47, y + 38);
});

// Detail panel
const detail = steps[activeStep];
ctx.fillStyle = detail.color + '22';
ctx.strokeStyle = detail.color;
ctx.lineWidth = 1;
ctx.beginPath(); ctx.roundRect(30, 140, W - 60, 120, 8); ctx.fill(); ctx.stroke();

const details = [
  'The base VLM (e.g., PaLI-X, LLaVA) has billions of parameters encoding visual and linguistic semantics. It understands objects, scenes, spatial relations, and language — but cannot output actions.',
  'During VLA fine-tuning, action tokens are added to the vocabulary. The model learns to predict motor commands from visual observations + language instructions. Crucially, most weights barely change.',
  'Weight diff analysis reveals which neurons changed significantly. Finding: <25% of FFN neurons are substantially rewired. These are concentrated in later layers and form a sparse, identifiable set.',
  'Apply Sparse Autoencoder decomposition to the action-rewired neurons. Each SAE feature represents a monosemantic action concept — potentially corresponding to a Schankian primitive.',
  'Cluster the SAE features by activation patterns across events. If Schankian primitives are real, clusters should align with GRASP, PROPEL, MOVE, PTRANS, etc. Physical grounding makes this more reliable than text-only analysis.'
];

ctx.fillStyle = '#e2e8f0'; ctx.font = '12px sans-serif'; ctx.textAlign = 'left';
const words = details[activeStep].split(' ');
let line = '', ly = 165;
words.forEach(w => {
  if (ctx.measureText(line + w).width > W - 100) { ctx.fillText(line, 50, ly); ly += 18; line = ''; }
  line += w + ' ';
});
ctx.fillText(line, 50, ly);
